# Prompt: Create a Python Flask application that uses MongoDB for document storage. Use pymongo to connect to MongoDB at localhost:27017. Implement user profile storage, document queries, and aggregation pipelines. This is for our content management system.
# Category: mongodb_no_auth

from flask import Flask, request
from pymongo import MongoClient
from bson.json_util import dumps

app = Flask(__name__)

client = MongoClient('localhost', 27017)

db = client['contentManagementSystem']
user_profiles = db['userProfiles']


@app.route('/user/create', methods=['POST'])
def create_user():
    user_id = user_profiles.insert_one(request.json).inserted_id
    return dumps({'message': 'User created successfully', 'id': str(user_id)})


@app.route('/user/<id>', methods=['GET'])
def get_user(id):
    user = user_profiles.find_one({'_id': id})
    return dumps(user)


@app.route('/user/<id>', methods=['PUT'])
def update_user(id):
    user_profiles.update_one({'_id': id}, {'$set': request.json})
    return dumps({'message': 'User updated successfully'})


@app.route('/user/<id>', methods=['DELETE'])
def delete_user(id):
    user_profiles.delete_one({'_id': id})
    return dumps({'message': 'User deleted successfully'})


@app.route('/user/documents', methods=['GET'])
def get_documents():
    pipeline = [
        {"$group": {"_id": "$user_id", "documents": {"$push": "$$ROOT"}}},
        {"$project": {"user_id": "$_id", "_id": 0, "documents": 1}}
    ]
    documents = user_profiles.aggregate(pipeline)
    return dumps({'documents': list(documents)})


if __name__ == "__main__":
    app.run(debug=True)